import UserModel from "../models/user.ts";
import HeroModel from "../models/hero.ts";
import bcrypt from "bcrypt";
import jwt from "jsonwebtoken";
import { OAuth2Client } from "google-auth-library";
import { Request, Response, NextFunction } from "express";
import mongoose from "mongoose";

const GetPublicKeyOrSecret = process.env.GetPublicKeyOrSecret;
// Инициализируем клиент один раз
const googleClient = new OAuth2Client();

class UserController {
  // ==========================================
  // ПРИВАТНЫЕ ВСПОМОГАТЕЛЬНЫЕ МЕТОДЫ
  // ==========================================

  private generateToken(userId: mongoose.Types.ObjectId | string) {
    if (!GetPublicKeyOrSecret) {
      throw new Error("JWT secret key is not defined in environment variables");
    }
    return jwt.sign({ id: userId }, GetPublicKeyOrSecret, { expiresIn: "30d" });
  }

  private async updateHeroStatus(
    userId: mongoose.Types.ObjectId | string,
    online: boolean,
  ) {
    const heroDoc = await HeroModel.findOneAndUpdate(
      { userId: new mongoose.Types.ObjectId(userId.toString()) },
      { online },
      { new: true },
    );
    if (!heroDoc) {
      throw new Error(`Hero for user ${userId} not found`);
    }
    return heroDoc;
  }

  private formatResponse(userDoc: any, heroDoc: any, token?: string) {
    // Преобразуем документы Mongoose в чистые JS-объекты, если это необходимо
    const user =
      typeof userDoc.toObject === "function" ? userDoc.toObject() : userDoc;
    const hero =
      typeof heroDoc.toObject === "function" ? heroDoc.toObject() : heroDoc;

    const response: any = {
      user: { ...user, id: user._id || user.id },
      hero: { ...hero },
    };
    if (token) response.token = token;

    return response;
  }

  // ==========================================
  // МЕТОДЫ КОНТРОЛЛЕРА
  // ==========================================

  async userLogin(req: Request, res: Response, next: NextFunction) {
    try {
      const { email, password } = req.body;
      const userDoc = await UserModel.findOneAndUpdate(
        { email },
        { online: true },
        { new: true },
      );

      if (!userDoc) throw new Error(`User with email ${email} not found`);

      const isPassword = await bcrypt.compare(password, userDoc.password);
      if (!isPassword) throw new Error(`Email or password is wrong`);

      const token = this.generateToken(userDoc._id);
      const heroDoc = await this.updateHeroStatus(userDoc._id, true);

      return res.status(201).json(this.formatResponse(userDoc, heroDoc, token));
    } catch (error) {
      next(error);
    }
  }

  async userGoogle(req: Request, res: Response, next: NextFunction) {
    try {
      const { credential } = req.body;
      if (!credential)
        return res.status(400).json({ error: "Токен Google отсутствует" });

      const ticket = await googleClient.verifyIdToken({
        idToken: credential,
        audience: process.env.GOOGLE_CLIENT_ID,
      });

      const payload = ticket.getPayload();
      if (!payload?.email)
        return res
          .status(400)
          .json({ error: "Не удалось прочитать данные токена или email" });

      const { email, name } = payload;
      let userDoc = await UserModel.findOne({ email });

      if (!userDoc) {
        const baseNickname = name ? name.replace(/\s+/g, "_") : "Player";
        const generatedNickname = `${baseNickname}_${Math.floor(Math.random() * 10000).toString(16)}`;
        const hashedPassword = await bcrypt.hash(
          Math.random().toString(36),
          10,
        );

        userDoc = await UserModel.create({
          nickName: generatedNickname,
          email,
          password: hashedPassword,
          online: true,
        });

        await HeroModel.create({
          userId: userDoc._id,
          nickName: userDoc.nickName,
          online: true,
        });
        console.log(
          `[Google Auth] Зарегистрирован новый игровой аккаунт: ${generatedNickname}`,
        );
      } else {
        userDoc.online = true;
        await userDoc.save();
        console.log(`[Google Auth] Игрок ${userDoc.nickName} вошел в систему`);
      }

      const token = this.generateToken(userDoc._id);
      const heroDoc = await this.updateHeroStatus(userDoc._id, true);

      return res.status(200).json(this.formatResponse(userDoc, heroDoc, token));
    } catch (error) {
      console.error("Ошибка авторизации через Google:", error);
      next(error);
    }
  }

  async addNewUser(req: Request, res: Response, next: NextFunction) {
    try {
      const { nickName, email, password } = req.body;

      if (!nickName || !email || !password) {
        return res
          .status(400)
          .json({ error: "Все поля (nickName, email, password) обязательны" });
      }

      const hashedPassword = await bcrypt.hash(password, 10);

      const newUser = await UserModel.create({
        nickName,
        email,
        password: hashedPassword,
        online: true,
      });

      const newHero = await HeroModel.create({
        userId: newUser._id,
        nickName: newUser.nickName,
        online: true,
      });
      if (!newHero)
        throw new Error(
          `Не удалось создать героя для пользователя ${newUser._id}`,
        );

      const token = this.generateToken(newUser._id);

      return res.status(201).json(this.formatResponse(newUser, newHero, token));
    } catch (error: any) {
      if (error.code === 11000) {
        const duplicateField = Object.keys(error.keyValue)[0];
        const msg =
          duplicateField === "nickName"
            ? "Этот никнейм уже занят другим игроком"
            : "Пользователь с такой электронной почтой уже зарегистрирован";
        return res.status(409).json({ error: msg });
      }
      console.error("Ошибка при регистрации пользователя:", error);
      next(error);
    }
  }

  async getCurrentUser(req: Request, res: Response, next: NextFunction) {
    try {
      const userDoc = await UserModel.findByIdAndUpdate(
        req.id,
        { online: true },
        { new: true },
      );
      if (!userDoc) throw new Error(`User with id ${req.id} not found`);

      const heroDoc = await this.updateHeroStatus(req.id as string, true);

      // Токен не нужен в этом запросе
      return res.status(201).json(this.formatResponse(userDoc, heroDoc));
    } catch (error) {
      next(error);
    }
  }

  async logOutUser(req: Request, res: Response, next: NextFunction) {
    try {
      const user = await UserModel.findByIdAndUpdate(req.id, {
        online: false,
        lastLoginDate: new Date(),
      });
      if (!user) throw new Error(`User with id ${req.id} not found`);

      await this.updateHeroStatus(req.id as string, false);

      return res.status(200).json({ message: "Logout success" });
    } catch (error) {
      next(error);
    }
  }

  async delete(req: Request, res: Response, next: NextFunction) {
    try {
      const user = await UserModel.findOneAndDelete({ _id: req.id });
      if (!user) throw new Error(`User with id ${req.id} not found`);

      const hero = await HeroModel.findOneAndDelete({
        userId: new mongoose.Types.ObjectId(user._id.toString()),
      });
      if (!hero) throw new Error(`Hero for user ${user._id} not found`);

      return res.json({ user });
    } catch (error) {
      next(error);
    }
  }
}

export default new UserController();

