import { Room, Client } from "colyseus";
import { UniverseState } from "./schemas/UniverseState.ts";
import { Player } from "./schemas/PlayerState.ts";
import { LocationManager } from "../game/managers/LocationManager.ts";
import { ChatManager } from "../game/managers/ChatManager.ts";
import HeroModel from "../models/hero.ts"; // Импорт твоей модели героя

export class UniverseRoom extends Room<UniverseState> {
  private locationManager!: LocationManager;
  private chatManager!: ChatManager;

  async onCreate(options: any) {
    this.setState(new UniverseState());
    this.locationManager = new LocationManager(this.state);
    this.chatManager = new ChatManager(this);

    await this.locationManager.init();

    this.setSimulationInterval(() => {
      this.locationManager.updateAllWorlds();
    }, 1000 / 60);

    // Слушаем перемещения
    this.onMessage("move", (client, data) => {
      const player = this.state.players.get(client.sessionId);
      if (player) {
        this.locationManager.handleMove(
          client.sessionId,
          player.locationId,
          data.x,
          data.z,
        );
      }
    });

    // Слушаем чат
    this.onMessage("chat_send", (client, data) => {
      this.chatManager.processMessage(client, data);
    });

    // Слушаем межпланетные перелеты
    this.onMessage("travel", (client, data) => {
      const player = this.state.players.get(client.sessionId);
      if (player && data.toLocationId) {
        this.locationManager.changeLocation(
          client.sessionId,
          player.locationId,
          data.toLocationId,
        );
      }
    });
  }

  // Игрок подключается к сокету
  async onJoin(client: Client, options: any) {
    const userId = options.userId;

    if (!userId) {
      console.error(
        `🚨 Клиент ${client.sessionId} не передал userId. Подключение разорвано.`,
      );
      client.leave();
      return;
    }

    try {
      // 1. Находим героя в MongoDB, закрепленного за этим пользователем
      const hero = await HeroModel.findOne({ userId });

      if (!hero) {
        console.error(`🚨 У пользователя ${userId} еще нет созданного героя!`);
        client.leave();
        return;
      }

      // 2. Ставим флаг онлайн в базе данных
      hero.online = true;
      await hero.save();
      console.log(
        `🚀 Герой ${hero.nickName} вошел в игру. Планета: ${hero.planet}`,
      );

      // 3. Переносим данные из твоей БД в синхронизируемый стейт Colyseus
      const player = new Player();
      player.id = client.sessionId;
      player.dbUserId = userId.toString();
      player.nickName = hero.nickName;
      player.locationId = hero.planet; // Синхронизируем планету
      player.x = hero.position?.x as number;
      player.y = hero.position?.y as number;
      player.z = hero.position?.z as number;
      this.state.players.set(client.sessionId, player);

      // 4. Инициализируем физическое тело на нужной планете с сохраненными координатами
      this.locationManager.handlePlayerJoin(
        client.sessionId,
        player.locationId,
        {
          x: player.x,
          y: player.y,
          z: player.z,
        },
      );
    } catch (error) {
      console.error(
        "🚨 Ошибка при авторизации/загрузке героя в комнату:",
        error,
      );
      client.leave();
    }
  }

  // Игрок отключается (закрыл вкладку, пропал интернет и т.д.)
  async onLeave(client: Client, consented: boolean) {
    const player = this.state.players.get(client.sessionId);

    if (player) {
      // Если игрок улетел дальше чем на 500м от центра (например, радиус планеты 100),
      // НЕ СОХРАНЯЙ эти координаты, они битые!
      const dist = Math.sqrt(player.x ** 2 + player.y ** 2 + player.z ** 2);
      if (dist > 400) {
        console.error(
          `⚠️ БАГ: Пытаемся сохранить битые координаты для ${player.nickName}: ${player.y}. Сохранение отменено!`,
        );
        // Здесь можно либо вообще не обновлять позицию,
        // либо принудительно сбросить ее на поверхность планеты
        player.y = 210;
        player.x = 0;
        player.z = 0;
      }

      try {
        // Обновляем позицию, планету и сбрасываем онлайн в твоей схеме Hero
        await HeroModel.findOneAndUpdate(
          { userId: player.dbUserId },
          {
            planet: player.locationId,
            position: {
              x: player.x,
              y: player.y,
              z: player.z,
            },
            online: false,
            updatedAt: new Date(),
          },
        );
        console.log(
          `💾 Данные героя ${player.nickName} успешно синхронизированы с MongoDB.`,
        );
      } catch (error) {
        console.error(
          `🚨 Не удалось сохранить координаты героя ${player.nickName}:`,
          error,
        );
      }

      // Чистим память сервера и физический движок
      this.locationManager.handlePlayerLeave(
        client.sessionId,
        player.locationId,
      );
      this.state.players.delete(client.sessionId);
    }
  }

  onDispose() {
    console.log("🧹 Комната вселенной уничтожена.");
  }
}

