  @type("number") x: number = 0;
  @type("number") y: number = 0;
  @type("number") z: number = 0;
}

import { Schema, type } from "@colyseus/schema";

export class PlanetState extends Schema {
  @type("string") id: string = "";
  @type("string") name: string = "";
  @type("number") radius: number = 0;
  // Координаты центра на случай, если решишь разносить их на клиенте
  @type("number") cx: number = 0;
  @type("number") cy: number = 0;
  @type("number") cz: number = 0;
}

import RAPIER from "@dimforge/rapier3d-compat";
import { PhysicsManager } from "../physics/PhysicsManager.ts";
import { UniverseState } from "../../wsRoom/schemas/UniverseState.ts";
import { PLANETS } from "../gameObjects/Planets.ts";
import { PlanetState } from "../../wsRoom/schemas/PlanetState.ts";

export class LocationManager {
  private worlds: Map<string, PhysicsManager> = new Map();
  private state: UniverseState;

  constructor(state: UniverseState) {
    this.state = state;
  }

  async init() {
    await RAPIER.init();

    Object.values(PLANETS).forEach((planet) => {
      // 1. Инициализируем изолированную физику сервера
      const worldPhysics = new PhysicsManager({
        center: planet.center,
        radius: planet.radius,
        gravityStrength: planet.gravityStrength,
      });
      worldPhysics.initGround();
      this.worlds.set(planet.id, worldPhysics);

      // 2. Публикуем данные в стейт комнаты. Клиент получит их ОДИН раз при коннекте.
      const planetState = new PlanetState();
      planetState.id = planet.id;
      planetState.name = planet.name;
      planetState.radius = planet.radius;
      planetState.cx = planet.center.x;
      planetState.cy = planet.center.y;
      planetState.cz = planet.center.z;

      this.state.planets.set(planet.id, planetState);
    });

    console.log(
      `🪐 Вселенная создана! На клиенты отправлено планет: ${this.state.planets.size}`,
    );
  }

  public handlePlayerJoin(
    id: string,
    targetLocation: string,
    coords?: { x: number; y: number; z: number }, // Добавили аргумент
  ) {
    const world = this.worlds.get(targetLocation);
    if (world) {
      // Передаем сохраненные координаты в PhysicsManager
      world.addPlayerBody(id, coords);
    }
  }

  public handlePlayerLeave(id: string, currentLocation: string) {
    const world = this.worlds.get(currentLocation);
    if (world) world.removePlayerBody(id);
  }

  public handleMove(
    id: string,
    locationId: string,
    dirX: number,
    dirZ: number,
  ) {
    const world = this.worlds.get(locationId);
    if (world) world.handlePlayerMove(id, { x: dirX, z: dirZ });
  }

  public changeLocation(id: string, fromLocation: string, toLocation: string) {
    const oldWorld = this.worlds.get(fromLocation);
    const newWorld = this.worlds.get(toLocation);
    const player = this.state.players.get(id);

    if (oldWorld && newWorld && player) {
      oldWorld.removePlayerBody(id);
      player.locationId = toLocation;
      newWorld.addPlayerBody(id);
      console.log(
        `🚀 Игрок ${id} переместился: ${fromLocation} -> ${toLocation}`,
      );
    }
  }

  public updateAllWorlds() {
    this.worlds.forEach((world) => {
      world.step((id, x, y, z) => {
        const player = this.state.players.get(id);
        if (player) {
          player.x = x;
          player.y = y;
          player.z = z;
        }
      });
    });
  }
}

import { Room, Client } from "colyseus";
import { UniverseState } from "../../wsRoom/schemas/UniverseState.ts";

export interface IChatMessage {
  senderId: string;
  senderName: string;
  targetId?: string; // Для ЛС
  text: string;
  type: "global" | "local" | "private";
  locationId?: string;
  timestamp: number;
}

export class ChatManager {
  private room: Room<UniverseState>;

  constructor(room: Room<UniverseState>) {
    this.room = room;
  }

  public processMessage(client: Client, data: any) {
    const sender = this.room.state.players.get(client.sessionId);
    if (!sender) return;

    const payload: IChatMessage = {
      senderId: client.sessionId,
      senderName: sender.nickName,
      text: data.text,
      type: data.type,
      locationId: sender.locationId,
      timestamp: Date.now(),
    };

    if (data.type === "private" && data.targetId) {
      payload.targetId = data.targetId;
    }

    // Рассылаем только тем, кто прямо сейчас в сети
    this.dispatchRealtime(client, payload);
  }

  private dispatchRealtime(client: Client, payload: IChatMessage) {
    switch (payload.type) {
      case "global":
        this.room.broadcast("chat_message", payload);
        break;

      case "local":
        this.room.broadcast("chat_message", payload, {
          // Colyseus typings may not include a `filter` option; cast to any to allow runtime filter
          filter: (otherClient: Client) => {
            const receiver = this.room.state.players.get(otherClient.sessionId);
            return receiver
              ? receiver.locationId === payload.locationId
              : false;
          },
        } as any);
        break;

      case "private":
        const targetClient = this.room.clients.find(
          (c) => c.sessionId === payload.targetId,
        );
        if (targetClient) {
          targetClient.send("chat_message", payload);
        }
        // Возвращаем автору, чтобы отобразить в его интерфейсе
        client.send("chat_message", payload);
        break;
    }
  }
}

import RAPIER from "@dimforge/rapier3d-compat";
import { SphericalUtils } from "./utils/SphericalUtils.ts";

export interface PlanetConfig {
  center: { x: number; y: number; z: number };
  radius: number;
  gravityStrength: number;
}

export class PhysicsManager {
  public world!: RAPIER.World;
  private bodies: Map<string, RAPIER.RigidBody> = new Map();
  private config: PlanetConfig;

  constructor(config: PlanetConfig) {
    this.config = config;
    this.world = new RAPIER.World({ x: 0.0, y: 0.0, z: 0.0 }); // Нулевая глобальная гравитация
  }

  public initGround() {
    const groundDesc = RAPIER.RigidBodyDesc.fixed().setTranslation(
      this.config.center.x,
      this.config.center.y,
      this.config.center.z,
    );
    const groundBody = this.world.createRigidBody(groundDesc);

    const groundColliderDesc = RAPIER.ColliderDesc.ball(this.config.radius);
    this.world.createCollider(groundColliderDesc, groundBody);

    // console.log(
    //   `🪐 Планета создана. Радиус: ${this.config.radius}м, Гравитация: ${this.config.gravityStrength}`,
    // );
  }

  public addPlayerBody(
    id: string,
    coords?: { x: number; y: number; z: number },
  ) {
    // 1. Определяем стартовую позицию
    let startX = 0;
    // ЧЕК СТРОКИ: исправлено на this.config.radius
    let startY = this.config.radius + 5.0;
    let startZ = 0;
    if (coords) {
      console.log("ЗАГРУЗКА ИЗ БД:", JSON.stringify(coords)); // Увидишь реальные числа прямо перед созданием физики
      startX = coords.x;
      startY = coords.y;
      startZ = coords.z;
    }

    // Если координаты переданы из базы данных, берем их
    if (coords) {
      startX = coords.x;
      startY = coords.y;
      startZ = coords.z;
    }

    // 2. Создаем динамическое жесткое тело в Rapier
    const rigidBodyDesc = RAPIER.RigidBodyDesc.dynamic()
      .setTranslation(startX, startY, startZ)
      .setLinearDamping(0.5) // Чтобы персонаж не скользил вечно
      .setAngularDamping(1.0); // Запрещаем телу хаотично вращаться сферой

    // ЧЕК СТРОКИ: исправлено на this.world
    const body = this.world.createRigidBody(rigidBodyDesc);

    // 3. Создаем капсулу-коллайдер для персонажа
    const colliderDesc = RAPIER.ColliderDesc.capsule(1.0, 0.5); // Высота и радиус капсулы
    // ЧЕК СТРОКИ: исправлено на this.world
    this.world.createCollider(colliderDesc, body);

    // 4. Сохраняем ссылку на тело в твою Map игроков внутри этого физического мира
    // ЧЕК СТРОКИ: исправлено на this.bodies
    this.bodies.set(id, body);
  }

  public removePlayerBody(id: string) {
    const body = this.bodies.get(id);
    if (body) {
      this.world.removeRigidBody(body);
      this.bodies.delete(id);
    }
  }

  public handlePlayerMove(id: string, clientInput: { x: number; z: number }) {
    const body = this.bodies.get(id);
    if (!body) return;

    // Вычисляем новую скорость через нашу утилиту
    const newVelocity = SphericalUtils.calculateSurfaceVelocity(
      body.translation(),
      body.linvel(),
      clientInput,
      this.config.center,
      8.0, // Скорость бега
    );

    body.setLinvel(newVelocity, true);
  }

  public step(onSync: (id: string, x: number, y: number, z: number) => void) {
    // Применяем гравитацию ко всем объектам через утилиту
    this.bodies.forEach((body) => {
      SphericalUtils.applyGravity(
        body,
        this.config.center,
        this.config.gravityStrength,
      );
    });

    this.world.step();

    this.bodies.forEach((body, id) => {
      const pos = body.translation();
      onSync(id, pos.x, pos.y, pos.z);
    });
  }
}

import RAPIER from "@dimforge/rapier3d-compat";

export class SphericalUtils {
  /**
   * Применяет силу гравитации к телу, притягивая его к центру планеты.
   * Эту функцию можно использовать для любых объектов на любых планетах.
   */
  static applyGravity(
    body: RAPIER.RigidBody,
    planetCenter: { x: number; y: number; z: number },
    gravityStrength: number,
  ) {
    const pos = body.translation();

    const dx = planetCenter.x - pos.x;
    const dy = planetCenter.y - pos.y;
    const dz = planetCenter.z - pos.z;

    const distance = Math.sqrt(dx * dx + dy * dy + dz * dz);

    // Если объект слишком близко к центру, гравитацию не применяем во избежание деления на ноль
    if (distance < 0.1) return;

    // Нормализованный вектор направления к центру
    const dirX = dx / distance;
    const dirY = dy / distance;
    const dirZ = dz / distance;

    const mass = body.mass();

    body.addForce(
      {
        x: dirX * gravityStrength * mass,
        y: dirY * gravityStrength * mass,
        z: dirZ * gravityStrength * mass,
      },
      true,
    );
  }

  /**
   * Рассчитывает новый вектор скорости для движения по поверхности сферы.
   * Возвращает объект {x, y, z} с новой скоростью.
   */
  static calculateSurfaceVelocity(
    pos: { x: number; y: number; z: number },
    currentVel: { x: number; y: number; z: number },
    clientInput: { x: number; z: number },
    planetCenter: { x: number; y: number; z: number },
    walkSpeed: number,
  ) {
    const dx = pos.x - planetCenter.x;
    const dy = pos.y - planetCenter.y;
    const dz = pos.z - planetCenter.z;
    const distance = Math.sqrt(dx * dx + dy * dy + dz * dz);

    if (distance === 0) return currentVel;

    // Вектор "Вверх" (от центра к объекту)
    const upX = dx / distance;
    const upY = dy / distance;
    const upZ = dz / distance;

    // Проекция ввода на касательную плоскость
    const dotInputUp = clientInput.x * upX + 0 * upY + clientInput.z * upZ;
    let tangentX = clientInput.x - dotInputUp * upX;
    let tangentY = 0 - dotInputUp * upY;
    let tangentZ = clientInput.z - dotInputUp * upZ;

    // Нормализация вектора движения
    const tangentLen = Math.sqrt(
      tangentX * tangentX + tangentY * tangentY + tangentZ * tangentZ,
    );
    if (tangentLen > 0.001) {
      tangentX /= tangentLen;
      tangentY /= tangentLen;
      tangentZ /= tangentLen;
    }

    // Сохраняем скорость падения (нормальную скорость)
    const currentNormalSpeed =
      currentVel.x * upX + currentVel.y * upY + currentVel.z * upZ;

    return {
      x: tangentX * walkSpeed + upX * currentNormalSpeed,
      y: tangentY * walkSpeed + upY * currentNormalSpeed,
      z: tangentZ * walkSpeed + upZ * currentNormalSpeed,
    };
  }
}

